// Build a weekly report from the ssuMCP public API.
// notices: { data: { items: [ { title, category, ... } ] } }
// meals:   { data: { days: [ { date, meals: [ { restaurant, type, menu[] } ] } ] } }
const noticeData = $input.first().json;
const mealData = $input.last().json;

const notices = noticeData.data?.items || [];
const days = mealData.data?.days || [];

const today = new Date();
const weekNum = Math.ceil(today.getDate() / 7);
const monthNames = ['1월','2월','3월','4월','5월','6월','7월','8월','9월','10월','11월','12월'];
const month = monthNames[today.getMonth()];

let report = `📅 **숭실대 주간 리포트 (${month} ${weekNum}주차)**\n\n`;

report += '📢 **최신 공지 (TOP 3)**\n';
const topNotices = notices.slice(0, 3);
if (topNotices.length === 0) {
  report += '• 새 공지 없음\n';
} else {
  topNotices.forEach(n => {
    report += `• [${n.category || '공지'}] ${n.title}\n`;
  });
}

report += '\n🍱 **오늘의 학식 (점심)**\n';
const todayStr = today.toISOString().slice(0, 10);
const day = days.find(d => d.date === todayStr) || days[0];
if (day) {
  const lunches = (day.meals || []).filter(m => m.type === 'LUNCH');
  if (lunches.length > 0) {
    lunches.slice(0, 2).forEach(m => {
      report += `• ${m.restaurant}: ${(m.menu || []).slice(0, 3).join(', ')}\n`;
    });
  } else {
    report += '• 점심 메뉴 정보 없음\n';
  }
} else {
  report += '• 식단 정보를 불러올 수 없습니다.\n';
}

report += '\n🔗 https://ssumcp.duckdns.org';

return [{ json: { report } }];
